import{_ as t,o,c as l,a5 as e}from"./chunks/framework.D9Kapg2s.js";const u=JSON.parse('{"title":"格式支持","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/formats.md","filePath":"zh/guide/formats.md"}'),s={name:"zh/guide/formats.md"};function r(i,a,n,d,c,h){return o(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="格式支持" tabindex="-1">格式支持 <a class="header-anchor" href="#格式支持" aria-label="Permalink to &quot;格式支持&quot;">​</a></h1><p>LinguaFlow 支持多种文件格式的翻译，每种格式有不同的处理方式。</p><h2 id="支持的格式" tabindex="-1">支持的格式 <a class="header-anchor" href="#支持的格式" aria-label="Permalink to &quot;支持的格式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>格式</th><th>扩展名</th><th>说明</th></tr></thead><tbody><tr><td>Markdown</td><td><code>.md</code>, <code>.markdown</code>, <code>.mdx</code></td><td>通用文档格式</td></tr><tr><td>HTML</td><td><code>.html</code>, <code>.htm</code></td><td>标记语言文档</td></tr><tr><td>DOCX</td><td><code>.docx</code></td><td>Word 文档</td></tr><tr><td>EPUB</td><td><code>.epub</code></td><td>电子书格式</td></tr><tr><td>SRT</td><td><code>.srt</code></td><td>SubRip 字幕格式</td></tr><tr><td>VTT</td><td><code>.vtt</code></td><td>WebVTT 字幕格式</td></tr><tr><td>ASS</td><td><code>.ass</code></td><td>Advanced SubStation Alpha 字幕格式</td></tr><tr><td>纯文本</td><td><code>.txt</code></td><td>纯文本文件</td></tr><tr><td>JSON</td><td><code>.json</code></td><td>JSON 结构化格式</td></tr><tr><td>YAML</td><td><code>.yaml</code>, <code>.yml</code></td><td>YAML 结构化格式</td></tr><tr><td>TOML</td><td><code>.toml</code></td><td>TOML 结构化格式</td></tr></tbody></table><h2 id="markdown" tabindex="-1">Markdown <a class="header-anchor" href="#markdown" aria-label="Permalink to &quot;Markdown&quot;">​</a></h2><p>Markdown 是 LinguaFlow 支持最完整的格式。</p><h3 id="markdown-特性" tabindex="-1">Markdown 特性 <a class="header-anchor" href="#markdown-特性" aria-label="Permalink to &quot;Markdown 特性&quot;">​</a></h3><ul><li><strong>格式保留</strong> — 保留标题、列表、表格等格式</li><li><strong>AST 解析</strong> — 基于 goldmark AST 的叶子块解析，精准定位可翻译单元</li><li><strong>代码块保护</strong> — 自动识别并保护代码块不被翻译</li><li><strong>链接保护</strong> — 保护 URL 和链接文本</li><li><strong>图片保留</strong> — 保留图片链接和 alt 文本</li></ul><h3 id="markdown-注意事项" tabindex="-1">Markdown 注意事项 <a class="header-anchor" href="#markdown-注意事项" aria-label="Permalink to &quot;Markdown 注意事项&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li>HTML 标签内的文本可能会被翻译</li><li>复杂的嵌套格式可能影响翻译质量</li></ul></div><h2 id="html" tabindex="-1">HTML <a class="header-anchor" href="#html" aria-label="Permalink to &quot;HTML&quot;">​</a></h2><p>HTML 格式保留标签结构，仅翻译文本节点。</p><h3 id="html-特性" tabindex="-1">HTML 特性 <a class="header-anchor" href="#html-特性" aria-label="Permalink to &quot;HTML 特性&quot;">​</a></h3><ul><li><strong>标签保护</strong> — 保护 HTML/XML 标签及其属性，仅翻译可读文本节点</li><li><strong>结构保留</strong> — 渲染时按字节区间回写译文，保持文档结构</li><li><strong>按块切段</strong> — 按块级元素（<code>p</code> / <code>h1-h6</code> / <code>li</code> / <code>td</code> 等）与 <code>&lt;title&gt;</code> 切段</li><li><strong>大小限制</strong> — 支持最大 16 MB 的 HTML 文件</li></ul><div class="info custom-block"><p class="custom-block-title">暂不翻译的内容</p><p><code>script</code> / <code>style</code> / <code>code</code> / <code>pre</code> 内的内容以及可翻译属性（如 <code>alt</code>、<code>title</code>）在当前版本中原样保留，不进入翻译段。</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>含 <code>&lt;ruby&gt;</code> 注音的 HTML 可配合执行配置中的 Ruby 注音处理（详见 <a href="/zh/guide/advanced.html">高级功能</a>）。</p></div><h2 id="docx" tabindex="-1">DOCX <a class="header-anchor" href="#docx" aria-label="Permalink to &quot;DOCX&quot;">​</a></h2><p>DOCX（<code>.docx</code>）解析器直接处理 Word 文档的内部 ZIP + XML 结构，无需依赖 Microsoft Word 或其它外部工具。</p><h3 id="docx-特性" tabindex="-1">DOCX 特性 <a class="header-anchor" href="#docx-特性" aria-label="Permalink to &quot;DOCX 特性&quot;">​</a></h3><ul><li><strong>ZIP 包结构保留</strong> — 原样保留原始包内文件及压缩方式，仅重写 <code>word/document.xml</code></li><li><strong>段落级定位</strong> — 按 <code>element_path</code> 定位 <code>&lt;w:p&gt;</code> 段落，保留段落属性与样式外壳</li><li><strong>内联语义</strong> — 粗体、斜体等内联语义以 HTML 表示，便于审校界面预览</li><li><strong>大小保护</strong> — 整包上限 100 MB，并对解压后的单个条目设有上限，防止解压炸弹攻击</li></ul><h3 id="docx-注意事项" tabindex="-1">DOCX 注意事项 <a class="header-anchor" href="#docx-注意事项" aria-label="Permalink to &quot;DOCX 注意事项&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>页眉页脚、批注、SmartArt、图表等非主文档段落内容可能不被翻译；建议翻译后用 Word 打开校对排版。</p></div><h2 id="epub-电子书" tabindex="-1">EPUB 电子书 <a class="header-anchor" href="#epub-电子书" aria-label="Permalink to &quot;EPUB 电子书&quot;">​</a></h2><p>EPUB 格式的翻译支持章节级别的管理。</p><h3 id="epub-特性" tabindex="-1">EPUB 特性 <a class="header-anchor" href="#epub-特性" aria-label="Permalink to &quot;EPUB 特性&quot;">​</a></h3><ul><li><strong>章节浏览</strong> — 按章节浏览电子书内容</li><li><strong>逐章翻译</strong> — 按章节进行翻译</li><li><strong>进度追踪</strong> — 按章节追踪翻译进度</li><li><strong>格式保留</strong> — 保留 HTML 内容和样式</li><li><strong>DRM 检测</strong> — 自动检测并拒绝 DRM 保护的文件</li><li><strong>最大文件限制</strong> — 支持最大 100MB 的 EPUB 文件</li></ul><h3 id="翻译流程" tabindex="-1">翻译流程 <a class="header-anchor" href="#翻译流程" aria-label="Permalink to &quot;翻译流程&quot;">​</a></h3><ol><li>上传 EPUB 文件</li><li>系统自动解析章节结构</li><li>选择章节进行翻译</li><li>查看翻译进度</li><li>导出翻译后的 EPUB</li></ol><div class="tip custom-block"><p class="custom-block-title">EPUB 翻译建议</p><ul><li>建议按章节顺序翻译，保持上下文连贯</li><li>使用术语表确保术语一致性</li></ul></div><h2 id="srt-字幕" tabindex="-1">SRT 字幕 <a class="header-anchor" href="#srt-字幕" aria-label="Permalink to &quot;SRT 字幕&quot;">​</a></h2><p>SubRip 字幕格式，常用于视频字幕。</p><h3 id="srt-格式示例" tabindex="-1">SRT 格式示例 <a class="header-anchor" href="#srt-格式示例" aria-label="Permalink to &quot;SRT 格式示例&quot;">​</a></h3><div class="language-srt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">srt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1</span></span>
<span class="line"><span>00:00:01,000 --&gt; 00:00:04,000</span></span>
<span class="line"><span>Hello, welcome to the tutorial.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2</span></span>
<span class="line"><span>00:00:05,000 --&gt; 00:00:08,000</span></span>
<span class="line"><span>Today we will learn about LinguaFlow.</span></span></code></pre></div><h3 id="srt-翻译特性" tabindex="-1">SRT 翻译特性 <a class="header-anchor" href="#srt-翻译特性" aria-label="Permalink to &quot;SRT 翻译特性&quot;">​</a></h3><ul><li><strong>时间码保留</strong> — 保留原始时间码</li><li><strong>序号保留</strong> — 保留字幕序号</li><li><strong>格式保留</strong> — 保留 SRT 格式结构</li></ul><h2 id="vtt-字幕" tabindex="-1">VTT 字幕 <a class="header-anchor" href="#vtt-字幕" aria-label="Permalink to &quot;VTT 字幕&quot;">​</a></h2><p>WebVTT 字幕格式，常用于 Web 视频。</p><h3 id="vtt-格式示例" tabindex="-1">VTT 格式示例 <a class="header-anchor" href="#vtt-格式示例" aria-label="Permalink to &quot;VTT 格式示例&quot;">​</a></h3><div class="language-vtt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vtt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WEBVTT</span></span>
<span class="line"><span></span></span>
<span class="line"><span>00:00:01.000 --&gt; 00:00:04.000</span></span>
<span class="line"><span>Hello, welcome to the tutorial.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>00:00:05.000 --&gt; 00:00:08.000</span></span>
<span class="line"><span>Today we will learn about LinguaFlow.</span></span></code></pre></div><h3 id="vtt-翻译特性" tabindex="-1">VTT 翻译特性 <a class="header-anchor" href="#vtt-翻译特性" aria-label="Permalink to &quot;VTT 翻译特性&quot;">​</a></h3><ul><li><strong>时间码保留</strong> — 保留原始时间码</li><li><strong>格式保留</strong> — 保留 VTT 格式结构</li></ul><h2 id="ass-字幕" tabindex="-1">ASS 字幕 <a class="header-anchor" href="#ass-字幕" aria-label="Permalink to &quot;ASS 字幕&quot;">​</a></h2><p>Advanced SubStation Alpha 字幕格式，支持更丰富的样式。</p><h3 id="ass-翻译特性" tabindex="-1">ASS 翻译特性 <a class="header-anchor" href="#ass-翻译特性" aria-label="Permalink to &quot;ASS 翻译特性&quot;">​</a></h3><ul><li><strong>样式保留</strong> — 保留 ASS 样式定义</li><li><strong>时间码保留</strong> — 保留原始时间码</li><li><strong>事件保留</strong> — 保留 ASS 事件结构</li></ul><div class="warning custom-block"><p class="custom-block-title">ASS 格式注意</p><p>ASS 格式较为复杂，翻译时请确保样式定义不被修改。</p></div><h2 id="纯文本" tabindex="-1">纯文本 <a class="header-anchor" href="#纯文本" aria-label="Permalink to &quot;纯文本&quot;">​</a></h2><p>纯文本格式的翻译是最简单的场景。</p><h3 id="纯文本翻译特性" tabindex="-1">纯文本翻译特性 <a class="header-anchor" href="#纯文本翻译特性" aria-label="Permalink to &quot;纯文本翻译特性&quot;">​</a></h3><ul><li><strong>逐段翻译</strong> — 按空行分段进行翻译</li><li><strong>编码支持</strong> — 支持 UTF-8 编码</li><li><strong>XUnity 格式支持</strong> — 自动检测 XUnity AutoTranslator 格式（key=value）</li></ul><h2 id="json" tabindex="-1">JSON <a class="header-anchor" href="#json" aria-label="Permalink to &quot;JSON&quot;">​</a></h2><p>JSON 结构化格式，适用于配置文件、本地化文件等。</p><h3 id="json-翻译特性" tabindex="-1">JSON 翻译特性 <a class="header-anchor" href="#json-翻译特性" aria-label="Permalink to &quot;JSON 翻译特性&quot;">​</a></h3><ul><li><strong>递归解析</strong> — 递归收集所有字符串叶子节点</li><li><strong>路径保留</strong> — 记录每个字符串的 JSON 路径</li><li><strong>格式保留</strong> — 保留 JSON 结构和缩进</li></ul><h2 id="yaml" tabindex="-1">YAML <a class="header-anchor" href="#yaml" aria-label="Permalink to &quot;YAML&quot;">​</a></h2><p>YAML 结构化格式，适用于配置文件、文档等。</p><h3 id="yaml-翻译特性" tabindex="-1">YAML 翻译特性 <a class="header-anchor" href="#yaml-翻译特性" aria-label="Permalink to &quot;YAML 翻译特性&quot;">​</a></h3><ul><li><strong>递归解析</strong> — 递归收集所有字符串叶子节点</li><li><strong>路径保留</strong> — 记录每个字符串的 YAML 路径</li><li><strong>格式保留</strong> — 保留 YAML 结构</li></ul><div class="warning custom-block"><p class="custom-block-title">YAML 格式限制</p><p>YAML 注释在翻译过程中可能无法保留。</p></div><h2 id="toml" tabindex="-1">TOML <a class="header-anchor" href="#toml" aria-label="Permalink to &quot;TOML&quot;">​</a></h2><p>TOML 结构化格式，适用于配置文件、本地化文件等。</p><h3 id="toml-翻译特性" tabindex="-1">TOML 翻译特性 <a class="header-anchor" href="#toml-翻译特性" aria-label="Permalink to &quot;TOML 翻译特性&quot;">​</a></h3><ul><li><strong>递归解析</strong> — 递归收集所有字符串叶子节点</li><li><strong>路径保留</strong> — 记录每个字符串的 TOML 路径</li><li><strong>格式保留</strong> — 保留 TOML 结构</li><li><strong>日期时间保留</strong> — TOML 的日期时间类型（<code>time.Time</code>）为非字符串叶子，不进入翻译段，渲染时原样保留</li></ul><div class="warning custom-block"><p class="custom-block-title">TOML 格式限制</p><p>TOML 注释在翻译过程中可能无法保留（通用反序列化机制限制）。JSON、YAML、TOML 三者共享同一解析器，浏览器/解析器会通过尝试解析来区分格式，避免误判。</p></div><h2 id="格式选择建议" tabindex="-1">格式选择建议 <a class="header-anchor" href="#格式选择建议" aria-label="Permalink to &quot;格式选择建议&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">选择建议</p><ul><li><strong>文档翻译</strong> — 使用 Markdown 格式</li><li><strong>HTML 内容</strong> — 使用 HTML 格式</li><li><strong>Word 文档</strong> — 使用 DOCX 格式</li><li><strong>电子书翻译</strong> — 使用 EPUB 格式</li><li><strong>视频字幕</strong> — 使用 SRT 或 VTT 格式</li><li><strong>配置文件</strong> — 使用 JSON / YAML / TOML 格式</li><li><strong>简单文本</strong> — 使用纯文本格式</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>阅读 <a href="/zh/guide/projects.html">项目管理</a> 了解如何上传和管理文件</li><li>阅读 <a href="/zh/guide/translation-config.html">翻译配置</a> 了解翻译配置选项</li></ul>`,68)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
